import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const Checkout = () => {
  const { cartItems, totalPrice, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  const [address, setAddress] = useState({
    address: '', city: '', postalCode: '', country: '',
  });
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  if (!user) {
    navigate('/login');
    return null;
  }

  const handleChange = (e) =>
    setAddress({ ...address, [e.target.name]: e.target.value });

  const handleOrder = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await api.post('/orders', {
        items: cartItems.map((item) => ({
          product: item._id,
          name: item.name,
          image: item.image,
          price: item.price,
          quantity: item.quantity,
        })),
        shippingAddress: address,
        totalPrice,
      });
      clearCart();
      setSuccess(true);
    } catch (err) {
      setError(err.response?.data?.message || 'Order failed');
    }
  };

  if (success) {
    return (
      <div style={{ textAlign: 'center', marginTop: '80px' }}>
        <h2>✅ Order Placed Successfully!</h2>
        <p>Thank you for shopping with us.</p>
        <button onClick={() => navigate('/orders')} style={styles.btn}>
          View My Orders
        </button>
      </div>
    );
  }

  return (
    <div style={{ padding: '30px', maxWidth: '560px', margin: '0 auto' }}>
      <h2>📦 Checkout</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}

      <div style={styles.summary}>
        <h3>Order Summary</h3>
        {cartItems.map((item) => (
          <p key={item._id}>
            {item.name} × {item.quantity} — ${(item.price * item.quantity).toFixed(2)}
          </p>
        ))}
        <hr />
        <strong>Total: ${totalPrice.toFixed(2)}</strong>
      </div>

      <form onSubmit={handleOrder}>
        <h3>Shipping Address</h3>
        {['address', 'city', 'postalCode', 'country'].map((field) => (
          <input
            key={field}
            name={field}
            placeholder={field.charAt(0).toUpperCase() + field.slice(1)}
            value={address[field]}
            onChange={handleChange}
            style={styles.input}
            required
          />
        ))}
        <button type="submit" style={styles.btn}>Place Order</button>
      </form>
    </div>
  );
};

const styles = {
  summary: { marginBottom: '20px', background: '#f9f9f9', padding: '16px', borderRadius: '10px' },
  input: { display: 'block', width: '100%', padding: '10px 14px', margin: '10px 0', borderRadius: '8px', border: '1px solid #ddd', fontSize: '15px', boxSizing: 'border-box' },
  btn: { width: '100%', padding: '12px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '16px', cursor: 'pointer', marginTop: '10px' },
};

export default Checkout;
